    @mcp.tool()
    async def transition_lead_status(
        id: Annotated[str, "The UUID of the lead to transition"],
        to_status: Annotated[str, "Target status. Valid statuses: new, enriched, contacted, replied, converted, rejected"],
    ) -> dict[str, Any]:
        """Transition a lead to a new status.

        Validates the transition is allowed by the pipeline definition.
        If the transition requires approval, creates an Approval record instead.
        """
        from uuid import UUID as _UUID

        from factory.core.database import get_session_factory
        from factory.generated.asos.lead.repository import LeadRepository

        factory = get_session_factory()
        async with factory() as session:
            repo = LeadRepository(session)
            entity = await repo.get(_UUID(id))
            if entity is None:
                return {"error": f"lead with id '{id}' not found"}

            current_status = entity.status
            result = _validate_transition("lead", current_status, to_status)

            if not result.get("allowed"):
                return {
                    "error": result.get("error", "Transition not allowed"),
                    "current_status": current_status,
                    "allowed_transitions": result.get("allowed_transitions"),
                }

            if result.get("approval_required"):
                from factory.modules.approvals.models import Approval  # noqa: F401
                from factory.modules.approvals.service import ApprovalService

                approval_svc = ApprovalService(session)
                approval = await approval_svc.create(
                    workflow_slug=workflow_slug,
                    action_type=result["approval_action_type"],
                    payload={
                        "entity_name": "lead",
                        "entity_id": id,
                        "from_status": current_status,
                        "to_status": to_status,
                    },
                    related_entity_id=_UUID(id),
                    requested_by="agent",
                )
                await session.commit()
                return {
                    "status": "approval_required",
                    "approval_id": str(approval.id),
                    "action_type": result["approval_action_type"],
                    "message": (
                        f"Transition from '{current_status}' to '{to_status}' requires approval. "
                        f"Approval '{approval.id}' created."
                    ),
                }

            entity.status = to_status
            await session.flush()
            await session.refresh(entity)
            await session.commit()

            from factory.generated.asos.lead.serialize import serialize_lead
            return {
                "status": "transitioned",
                "from_status": current_status,
                "to_status": to_status,
                "entity": serialize_lead(entity),
            }

